-- 0061_multicompany_company_id.sql — Phase 0a of the multi-company merge.
-- Design: docs/2026-07-多公司合并设计.md (locked). Makes the DB multi-company-
-- ready: a companies master (2990 + Houzs) and a company_id FK on every
-- per-company (financial/order/catalog/supplier/customer) and cross-company
-- (TMS / Service Cases) table. All existing rows back-fill to the Houzs
-- company. SHARED masters (users/roles/positions/departments/permissions,
-- audit, mail, branding) and AMBIGUOUS tables get NO company_id (see report).
--
-- ADDITIVE + idempotent + re-run-safe. Each per-table change is one single-
-- line DO block guarded by to_regclass, so (a) a table absent from this DB is
-- skipped rather than erroring, and (b) the pg-migrate ';\n' splitter keeps
-- each block intact. scm tables are schema-qualified; the companies table +
-- all FKs live in public. NOT applied here — owner applies before deploy.

-- 1) companies master ------------------------------------------------------
CREATE TABLE IF NOT EXISTS public.companies (
  id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  code text NOT NULL UNIQUE,
  name text NOT NULL,
  is_active integer NOT NULL DEFAULT 1,
  created_at timestamptz NOT NULL DEFAULT now()
);

INSERT INTO public.companies (code, name) VALUES ('HOUZS', 'Houzs Century') ON CONFLICT (code) DO NOTHING;
INSERT INTO public.companies (code, name) VALUES ('2990', '2990''s Home') ON CONFLICT (code) DO NOTHING;

-- 2) PER-COMPANY (scm schema) — scoped to active company ------------------------------------------------------
-- scm.mfg_sales_orders
DO $$ BEGIN IF to_regclass('scm.mfg_sales_orders') IS NOT NULL THEN ALTER TABLE scm.mfg_sales_orders ADD COLUMN IF NOT EXISTS company_id bigint; UPDATE scm.mfg_sales_orders SET company_id = (SELECT id FROM public.companies WHERE code = 'HOUZS') WHERE company_id IS NULL; ALTER TABLE scm.mfg_sales_orders ALTER COLUMN company_id SET NOT NULL; ALTER TABLE scm.mfg_sales_orders DROP CONSTRAINT IF EXISTS mfg_sales_orders_company_id_fkey; ALTER TABLE scm.mfg_sales_orders ADD CONSTRAINT mfg_sales_orders_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(id); CREATE INDEX IF NOT EXISTS idx_mfg_sales_orders_company_id ON scm.mfg_sales_orders (company_id); END IF; END $$;

