-- scm.scan_jobs — background scan-to-DRAFT-SO jobs. Per-company: a scan builds
-- a DRAFT SO for the active company; tag the job so each company sees its own
-- scan queue. Existing rows back-fill to HOUZS.
DO $$ BEGIN IF to_regclass('scm.scan_jobs') IS NOT NULL THEN ALTER TABLE scm.scan_jobs ADD COLUMN IF NOT EXISTS company_id bigint; UPDATE scm.scan_jobs SET company_id = (SELECT id FROM public.companies WHERE code = 'HOUZS') WHERE company_id IS NULL; ALTER TABLE scm.scan_jobs ALTER COLUMN company_id SET NOT NULL; ALTER TABLE scm.scan_jobs DROP CONSTRAINT IF EXISTS scan_jobs_company_id_fkey; ALTER TABLE scm.scan_jobs ADD CONSTRAINT scan_jobs_company_id_fkey FOREIGN KEY (company_id) REFERENCES public.companies(id); CREATE INDEX IF NOT EXISTS idx_scan_jobs_company_id ON scm.scan_jobs (company_id); END IF; END $$;

-- scm.product_model_photos — per-Model photo gallery. Catalog is per-company
